#include <stdio.h>
#include <sys/mman.h>
#include <unistd.h>
#include <string.h>
#include <signal.h>
#include <setjmp.h>

static jmp_buf jump_buf;
static void handler(int sig) {
    (void)sig;
    longjmp(jump_buf, 1);
}

int main(void) {
    long page = sysconf(_SC_PAGESIZE);
    printf("Page size: %ld\n", page);
    void *ptr = mmap(NULL, (size_t)page,
        PROT_READ | PROT_WRITE,
        MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (ptr == MAP_FAILED) { perror("mmap"); return 1; }
    strcpy((char *)ptr, "protected data");
    printf("Before protect: %s\n", (char *)ptr);
    int rc = ____(ptr, (size_t)page, ____);
    printf("mprotect result: %d\n", rc);
    signal(SIGSEGV, handler);
    if (setjmp(jump_buf) == 0) {
        ((char *)ptr)[0] = 'X';
        printf("Write succeeded (unexpected)\n");
    } else {
        printf("SIGSEGV caught: write blocked\n");
    }
    printf("Read after protect: %s\n", (char *)ptr);
    munmap(ptr, (size_t)page);
    return 0;
}

