/* == EXEMPLE: mprotect PROT_NONE ====================== */
static jmp_buf ex_jmp;
static void ex_handler(int sig) { (void)sig; longjmp(ex_jmp, 1); }
void example_none(void) {
    long pg = sysconf(_SC_PAGESIZE);
    void *p = mmap(NULL, (size_t)pg, PROT_READ|PROT_WRITE, MAP_PRIVATE|MAP_ANONYMOUS, -1, 0);
    mprotect(p, (size_t)pg, PROT_NONE);
    signal(SIGSEGV, ex_handler);
    if (setjmp(ex_jmp) == 0) { volatile char c = ((char*)p)[0]; (void)c; }
    else printf("PROT_NONE: even read blocked\n");
    munmap(p, (size_t)pg);
}

